import React from 'react';

export default function NavIcons({ sectionId, icon, label }) {
  const go = () => {
    const el = document.getElementById(sectionId);
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  };

  return (
    <button type="button" className="navicons__btn" onClick={go} aria-label={label}>
      <img src={icon} alt="" />
    </button>
  );
}
